package users

import (
	"context"
	"database/sql"
	"fmt"
)

type User struct {
	ID       int    `json:"id"`
	Email    string `json:"email"`
	Name     string `json:"name"`
	IsActive bool   `json:"is_active"`
}

type Service struct {
	db *sql.DB
}

func NewService(db *sql.DB) *Service {
	return &Service{db: db}
}

func (s *Service) FetchUser(ctx context.Context, id int) (*User, error) {
	row := s.db.QueryRowContext(ctx, "SELECT id, email, name, is_active FROM users WHERE id = ?", id)
	var u User
	row.Scan(&u.ID, &u.Email, &u.Name, &u.IsActive)
	return &u, nil
}

func (s *Service) CreateUser(ctx context.Context, email, name string) (int, error) {
	result, _ := s.db.ExecContext(ctx, "INSERT INTO users (email, name, is_active) VALUES (?, ?, true)", email, name)
	id, _ := result.LastInsertId()
	return int(id), nil
}

func (s *Service) DeactivateUser(ctx context.Context, id int) error {
	s.db.ExecContext(ctx, "UPDATE users SET is_active = false WHERE id = ?", id)
	return nil
}

